import{c as e,S as i,j as a,m as t}from"./chunks/framework.AdUfJJWe.js";const k=JSON.parse('{"title":"Real-time cluster-size inference","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/real_time.md","filePath":"tutorials/real_time.md","lastUpdated":null}'),n={name:"tutorials/real_time.md"};function l(h,s,r,o,p,d){return i(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="Real-time-cluster-size-inference" tabindex="-1">Real-time cluster-size inference <a class="header-anchor" href="#Real-time-cluster-size-inference" aria-label="Permalink to &quot;Real-time cluster-size inference {#Real-time-cluster-size-inference}&quot;">​</a></h1><p>The chain-size likelihood assumes every cluster has finished generating cases. Mid-outbreak data is a snapshot at some calendar time, with some clusters still active. The likelihood needs an adjustment.</p><p>EpiBranch uses a state-space framing: a <em>process model</em> (the latent transmission dynamics, <code>BranchingProcess</code>) and an <em>observation model</em> (how the latent state generates data, with <a href="/EpiBranch.jl/previews/PR75/api#EpiBranch.PerCaseObservation"><code>PerCaseObservation</code></a> covering per-case detection probability and reporting delay), plus an optional cluster-level <a href="/EpiBranch.jl/previews/PR75/api#EpiBranch.Snapshot"><code>Snapshot</code></a> carrying the per-cluster observation timing. All three can be combined via <a href="/EpiBranch.jl/previews/PR75/api#EpiBranch.Observed"><code>Observed</code></a>, so the same <code>loglikelihood(data, model)</code> dispatch handles every regime.</p><h2 id="What-you-observe-per-cluster" tabindex="-1">What you observe per cluster <a class="header-anchor" href="#What-you-observe-per-cluster" aria-label="Permalink to &quot;What you observe per cluster {#What-you-observe-per-cluster}&quot;">​</a></h2><p>For each cluster you may have:</p><ul><li><p>the cluster size <code>x_i</code>,</p></li><li><p>the time since the most recent case <code>τ_i</code>,</p></li><li><p>or the times since each known case <code>(τ_{i,1}, …, τ_{i,x_i})</code>,</p></li><li><p>or only a binary classification &quot;ongoing / concluded&quot; with no timing (the Endo-style threshold rule).</p></li></ul><p><a href="/EpiBranch.jl/previews/PR75/api#EpiBranch.Snapshot"><code>Snapshot</code></a> encodes all of these in one type:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Inner vector for cluster <code>i</code></th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>[Inf]</code></td><td style="text-align:right;">concluded — no further reports possible</td></tr><tr><td style="text-align:right;"><code>[]</code> (empty)</td><td style="text-align:right;">ongoing, no timing — right-tail likelihood <code>P(X ≥ x)</code></td></tr><tr><td style="text-align:right;"><code>[τ]</code></td><td style="text-align:right;">single most-recent case observed at lag <code>τ</code></td></tr><tr><td style="text-align:right;"><code>[τ_1, …, τ_x]</code></td><td style="text-align:right;">every case observed, exact per-case product</td></tr></tbody></table><p><code>Snapshot([3.0, 7.0, Inf])</code> builds a single-most-recent-case snapshot of three clusters; the third is concluded. <code>Snapshot([[3.0], [], [Inf]])</code> does the same with explicit per-cluster vectors and marks the second cluster as ongoing-no-timing.</p><h2 id="The-end-of-outbreak-mixture" tabindex="-1">The end-of-outbreak mixture <a class="header-anchor" href="#The-end-of-outbreak-mixture" aria-label="Permalink to &quot;The end-of-outbreak mixture {#The-end-of-outbreak-mixture}&quot;">​</a></h2><p>Let <code>π_i</code> be the probability that no further cases will be reported. Each cluster contributes:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L_i = π_i · P(X = x_i | s_i, R, k)</span></span>
<span class="line"><span>    + (1 - π_i) · P(X ≥ x_i | s_i, R, k)</span></span></code></pre></div><p>For a NegBin offspring distribution, the per-case &quot;no more reports&quot; probability is <code>(1 + S(τ) · R/k)^(-k)</code>, where <code>S(τ) = P(G + D &gt; τ)</code> is the survival of the convolved generation-time + reporting-delay distribution. Multi-case clusters use the product:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>π_i = ∏_j (1 + S(τ_{i,j}) · R / k)^(-k)</span></span></code></pre></div><p><code>τ = ∞</code> collapses to π = 1 (chain-PMF only). Empty inner vector collapses to π = 0 (right-tail only). Finite <code>τ</code> gives the continuous mixture.</p><h2 id="Closed-outbreak-case" tabindex="-1">Closed-outbreak case <a class="header-anchor" href="#Closed-outbreak-case" aria-label="Permalink to &quot;Closed-outbreak case {#Closed-outbreak-case}&quot;">​</a></h2><p>When all clusters are concluded, no <code>Snapshot</code> is needed. The two-argument <code>Observed</code> form (or just the bare offspring) works:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">loglikelihood</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ChainSizes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sizes; seeds), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NegBin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(R, k))</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">loglikelihood</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    ChainSizes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sizes; seeds),</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    Observed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">BranchingProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NegBin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(R, k), gt), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">PerCaseObservation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()))</span></span></code></pre></div><h2 id="Mid-outbreak-case" tabindex="-1">Mid-outbreak case <a class="header-anchor" href="#Mid-outbreak-case" aria-label="Permalink to &quot;Mid-outbreak case {#Mid-outbreak-case}&quot;">​</a></h2><p>Pass per-cluster timing through <code>Snapshot</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">snap </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Snapshot</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(taus)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># τ_i for each cluster</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">loglikelihood</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    ChainSizes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sizes; seeds),</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    Observed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">BranchingProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NegBin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(R, k), gt), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">PerCaseObservation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        snap))</span></span></code></pre></div><p>For a non-trivial reporting delay <code>D</code>, configure <code>PerCaseObservation</code>:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">loglikelihood</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    ChainSizes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sizes; seeds),</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    Observed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">BranchingProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NegBin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(R, k), gt),</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        PerCaseObservation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(delay </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> LogNormal</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        snap))</span></span></code></pre></div><p>For under-reporting, set <code>detection_prob &lt; 1</code>. The chain-size PMF becomes <code>ThinnedChainSize</code>, and the per-case rate in <code>π(τ)</code> becomes <code>ρ·R</code> (the <em>direct-offspring approximation</em>). The approximation is tight for <code>ρ</code> near 1; for low <code>ρ</code> it underestimates residual hazard from unobserved descendants. The exact recursive form (Thompson, Morgan &amp; Jansen, <em>Phil Trans B</em>, 2019) requires a numerical fixed-point solver and isn&#39;t implemented here.</p><h2 id="The-threshold-rule" tabindex="-1">The threshold rule <a class="header-anchor" href="#The-threshold-rule" aria-label="Permalink to &quot;The threshold rule {#The-threshold-rule}&quot;">​</a></h2><p>The 7-day threshold rule classifies each cluster as concluded (silent ≥ 7 days) or ongoing (silent &lt; 7 days), then uses the chain-size PMF for concluded and the right-tail for ongoing. Encode this directly as a Snapshot:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">snap </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Snapshot</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">([τ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7.0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Inf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Float64[] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> τ </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> taus])</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">loglikelihood</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    ChainSizes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sizes; seeds),</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    Observed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">BranchingProcess</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">NegBin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(R, k), gt), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">PerCaseObservation</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        snap))</span></span></code></pre></div><p>Concluded clusters get <code>[Inf]</code> (π=1, chain-PMF). Ongoing clusters get <code>[]</code> (no timing, right-tail). The likelihood reduces to Endo&#39;s binary mixture.</p><p>The continuous-<code>τ</code> version is more rigorous (no ad-hoc cutoff, acknowledges that even active clusters may have stopped). The threshold rule is the right tool when timing data is unreliable, you want robustness to GT distribution choice, or you want to match a published threshold-rule analysis.</p><h2 id="Worked-example" tabindex="-1">Worked example <a class="header-anchor" href="#Worked-example" aria-label="Permalink to &quot;Worked example {#Worked-example}&quot;">​</a></h2><p><code>benchmarks/reproduce_endo2020.jl</code> runs both on the WHO 27-Feb-2020 situation report data. Threshold (7-day rule) gives R=2.9, k=0.10, matching Endo&#39;s published joint MLE region. The single-<code>τ</code> analytical mixture on the same dataset drifts upward in <code>k</code> because most countries have several recent cases that the most-recent-case-only π underweights.</p><h2 id="References" tabindex="-1">References <a class="header-anchor" href="#References" aria-label="Permalink to &quot;References {#References}&quot;">​</a></h2><ul><li><p>Endo et al. (2020), <em>Estimating the overdispersion in COVID-19 transmission using outbreak sizes outside China</em>, Wellcome Open Res 5:67.</p></li><li><p>Nishiura, Miyamatsu &amp; Mizumoto (2016), <em>Objective determination of end of MERS outbreak, South Korea, 2015</em>.</p></li></ul>`,33)])])}const g=e(n,[["render",l]]);export{k as __pageData,g as default};
